def run_weekly_triage(
    open_items: list,
    sprint_capacity_days: float,
    reliability_budget_pct: float,
) -> dict:
    reliability_capacity = sprint_capacity_days * reliability_budget_pct
    scored = [(ai, compute_priority_score(ai)) for ai in open_items]
    scored.sort(key=lambda x: x[1], reverse=True)
    sprint_plan = []
    remaining_capacity = reliability_capacity
    overflow = []
    for ai, score in scored:
        estimated_days = estimate_effort_days(ai)
        if score >= 15 or remaining_capacity >= estimated_days:
            if remaining_capacity >= estimated_days:
                sprint_plan.append(ai)
                remaining_capacity -= estimated_days
            else:
                # P1-band: add even if over budget, flag for EM review
                if score >= 15:
                    sprint_plan.append(ai)
        else:
            overflow.append(ai)
    return {
        "sprint_plan": sprint_plan,
        "overflow": overflow,
        "capacity_used": reliability_capacity - remaining_capacity,
        "capacity_total": reliability_capacity,
    }

@dataclass
class CrossTeamActionItem:
    parent_id: str             # virtual item representing the full cross-team work
    component_ids: list[str]   # one per team, each a standard ActionItem
    coordinator: str           # IC or EM of the originating team

    def is_complete(self, all_items: dict[str, object]) -> bool:
        return all(
            all_items[cid].state.value == "closed"
            for cid in self.component_ids
            if cid in all_items
        )

    def blocking_components(self, all_items: dict[str, object]) -> list[str]:
        return [
            cid for cid in self.component_ids
            if cid in all_items and all_items[cid].state.value not in ("closed",)
        ]

